#!/usr/bin/env python3
"""
parse_gng_status.py
Reads a filled go_no_go_checklist.yaml and prints a formatted summary
with pass/fail tallies and the final decision.

Usage:
    python parse_gng_status.py go_no_go_checklist.yaml
"""
import sys
import yaml

def load_checklist(path: str) -> dict:
    with open(path) as f:
        return yaml.safe_load(f)

def evaluate_criteria(checklist: dict) -> tuple:
    passed, failed_hard, failed_soft = [], [], []
    for category, items in checklist.get("criteria_categories", {}).items():
        for item in items:
            status = item.get("status")
            gate = item.get("gate", "soft")
            label = f"[{item['id']}] {item['description']}"
            if status == "pass":
                passed.append(label)
            elif status == "exception":
                failed_soft.append(label + " (exception accepted)")
            elif gate == "hard":
                failed_hard.append(label)
            else:
                failed_soft.append(label)
    return passed, failed_hard, failed_soft

def summarize_votes(checklist: dict) -> dict:
    votes = {"go": [], "no-go": [], "conditional": [], "pending": []}
    for participant in checklist.get("participants", []):
        vote = participant.get("vote") or "pending"
        votes.setdefault(vote, []).append(participant["name"])
    return votes

def print_summary(checklist: dict) -> None:
    launch = checklist.get("launch", {})
    print("\n=== GO/NO-GO FORUM SUMMARY ===")
    print(f"Service  : {launch.get('service')}")
    print(f"Version  : {launch.get('version')}")
    print(f"Date     : {launch.get('target_date')}")
    print(f"Authority: {launch.get('decision_authority')}")

    passed, hard_fails, soft_fails = evaluate_criteria(checklist)
    total = len(passed) + len(hard_fails) + len(soft_fails)
    print(f"\nCriteria ({total} total):")
    print(f"  Passed     : {len(passed)}")
    print(f"  Hard fails : {len(hard_fails)}")
    print(f"  Soft fails : {len(soft_fails)}")

    if hard_fails:
        print("\n  HARD GATE FAILURES (launch blocking):")
        for h in hard_fails:
            print(f"    - {h}")
    if soft_fails:
        print("\n  Soft gate failures (exception or remediation needed):")
        for s in soft_fails:
            print(f"    ~ {s}")

    votes = summarize_votes(checklist)
    print(f"\nVotes:")
    print(f"  Go          : {votes.get('go', [])}")
    print(f"  No-go       : {votes.get('no-go', [])}")
    print(f"  Conditional : {votes.get('conditional', [])}")
    print(f"  Pending     : {votes.get('pending', [])}")

    outcome = checklist.get("outcome", {})
    decision = outcome.get("decision") or ("no-go" if hard_fails else "pending")
    print(f"\nDecision: {decision.upper()}")

    if outcome.get("conditions"):
        print("Conditions attached:")
        for c in outcome["conditions"]:
            print(f"  * {c}")
    if outcome.get("no_go_blockers"):
        print("Blockers recorded:")
        for b in outcome["no_go_blockers"]:
            print(f"  * {b}")
    if outcome.get("next_steps"):
        print(f"Next steps: {outcome['next_steps']}")

if __name__ == "__main__":
    path = sys.argv[1] if len(sys.argv) > 1 else "go_no_go_checklist.yaml"
    checklist = load_checklist(path)
    print_summary(checklist)
